// 1. Acessamos o array de colunas que vem do nó do Monday
const columns = items[0].json.column_values;

// 2. Procuramos o objeto dentro do array que possui o id "text1"
const targetColumn = columns.find(column => column.id === "text1");

// 3. Retornamos o valor do campo 'text' se ele for encontrado
return {
  opportunityID: targetColumn ? targetColumn.text : "ID não encontrado"
};

// 1. Função auxiliar para converter milissegundos (start) em formato M:SS
const formatTime = (ms) => {
  const totalSeconds = Math.floor(ms / 1000);
  const minutes = Math.floor(totalSeconds / 60);
  const seconds = totalSeconds % 60;
  return `${minutes}:${seconds.toString().padStart(2, '0')}`;
};

// 2. Acessamos a estrutura: rows[0] -> TRANSCRIPT
const rows = items[0].json.rows[0];
const transcriptBlocks = rows.TRANSCRIPT;

// 3. Mapeamos os blocos mantendo o ID original do locutor
const formattedTranscript = transcriptBlocks.map(block => {
  // Pega o tempo de início da primeira frase do bloco de fala
  const startTime = formatTime(block.sentences[0].start);

  // Usa o speakerId original do JSON
  const speakerId = block.speakerId;

  // Une todas as frases (text) deste bloco com espaço
  const text = block.sentences.map(s => s.text).join(' ');

  // Formata conforme o modelo desejado: "Tempo | ID \n Texto"
  return `${startTime} | ${speakerId}\n${text}`;
}).join('\n\n'); // Adiciona linha em branco entre blocos de fala

// 4. Retorna um único item com o texto completo
return {
  transcript_final: `Transcript\n\n${formattedTranscript}`
};

